#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int a = 1; a <= 1000000; a++) {
            int freqA = 0;
            for (int i = 0; i < N; i++) {
                if (arr[i] == a) freqA++;
            }
            for (int b = 1; b <= 1000000; b++) {
                int freqB = 0;
                for (int i = 0; i < N; i++) {
                    if (arr[i] == b) freqB++;
                }
                if (freqA >= b && freqB >= a) count++;
            }
        }
        printf("%d\n", count);
        free(arr);
    }
    return 0;
}

