            freq[arr[i]]++;
        }
        int count = 0;
        for (auto& it : freq) {
            int a = it.first;
            int freqA = it.second;
            for (auto& it2 : freq) {
                int b = it2.first;
                int freqB = it2.second;
                if (freqA >= b && freqB >= a) count++;
            }
        }
        cout << count << endl;
        delete[] arr;
    }
    return 0;
}

